def cache_result(prefix=None, ttl=None):
    def decorator(func):
        cache_prefix = prefix or func.__name__
        cache_ttl = ttl if ttl is not None else app.config["CACHE_TTL_SECONDS"]

        @wraps(func)
        def wrapper(*args, **kwargs):
            key = _cache_key(cache_prefix, args, kwargs)
